using System.Net;
using System.Net.Http;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change: HttpClientFactory now uses SocketsHttpHandler by default.
// The cast to HttpClientHandler would throw InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler with an explicit handler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });

// Breaking change: Trace-level HttpClientFactory logs now redact all header
// values by default, which breaks header-debugging workflows.
// Fix: allowlist the specific non-sensitive headers you need to inspect.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Forwarded-For"
        && h != "X-Request-Id"
        && h != "Cache-Control"
        && h != "Content-Type"
        && h != "Accept"));

// Breaking change: ForwardedHeaders middleware now ignores X-Forwarded-*
// headers from proxies not in KnownProxies / KnownNetworks.
// Fix: register your reverse-proxy address(es).
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse-proxy IP(s)
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});

// Breaking change: ValidateOnBuild / ValidateScopes are now enabled in
// development by default. The singleton CacheService that resolves a scoped
// IUserService will throw at startup. Fix the captive-dependency bug by
// making CacheService scoped (or IUserService singleton, depending on intent).

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

